def load_config(path: str) -> dict:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def normalize_tenants(cfg: dict) -> List[dict]:
    tenants = cfg.get("tenants", [])
    if not isinstance(tenants, list):
        raise ValueError("config 'tenants' must be a list")
    out: List[dict] = []
    for t in tenants:
        if not isinstance(t, dict):
            raise ValueError("each tenant must be an object")
        if "app" not in t and "vhost" not in t:
            raise ValueError("each tenant must include 'app' or 'vhost'")
        app = t.get("app") or t.get("vhost")
        vhost = t.get("vhost") or f"/{app}"
        user = t.get("user") or f"{app}_user"
        password = t.get("password")
        tags = t.get("tags", [])
        permissions = t.get("permissions", {})
        configure = permissions.get("configure", "")
        write = permissions.get("write", ".*")
        read = permissions.get("read", ".*")

        topic_permissions = t.get("topic_permissions", [])
        limits = t.get("limits", {})
        policies = t.get("policies", [])
        parameters = t.get("parameters", [])

        out.append(
            {
                "app": app,
                "vhost": vhost,
                "description": t.get("description", f"vhost for {app}"),
                "user": user,
                "password": password,
                "password_hash": t.get("password_hash"),
                "hashing_algorithm": t.get("hashing_algorithm"),
                "tags": tags,
                "permissions": {"configure": configure, "write": write, "read": read},
                "topic_permissions": topic_permissions,
                "limits": limits,
                "policies": policies,
                "parameters": parameters,
                "tracing": t.get("tracing"),
            }
        )
    return out


def apply(manager: RabbitMQManager, cfg: dict, fail_on_missing_password: bool = True) -> None:
    tenants = normalize_tenants(cfg)
    for t in tenants:
        vhost = t["vhost"]
        manager.ensure_vhost(vhost, description=t.get("description"), tags=t.get("vhost_tags"), tracing=t.get("tracing"))

        user = t["user"]
        password = t.get("password")
        password_hash = t.get("password_hash")
        hashing_algorithm = t.get("hashing_algorithm")
        if password is None and password_hash is None:
            if fail_on_missing_password:
                raise ValueError(f"Missing password (or password_hash) for user '{user}' (tenant '{t['app']}')")
        else:
            manager.ensure_user(
                user,
                password=password,
                tags=t.get("tags", []),
                hashing_algorithm=hashing_algorithm,
                password_hash=password_hash,
            )

        perms = t["permissions"]
        manager.ensure_permissions(vhost, user, configure=perms.get("configure", ""), write=perms.get("write", ".*"), read=perms.get("read", ".*"))

        for tp in t.get("topic_permissions", []) or []:
            if not isinstance(tp, dict) or "exchange" not in tp:
                raise ValueError(f"topic_permissions entries must be objects with 'exchange' (tenant '{t['app']}')")
            manager.ensure_topic_permissions(
                vhost,
                user,
                exchange=tp["exchange"],
                write=tp.get("write", ".*"),
                read=tp.get("read", ".*"),
            )

        limits = t.get("limits", {}) or {}
        if "user" in limits:
            ul = limits["user"] or {}
            manager.ensure_user_limit(user, max_connections=ul.get("max_connections"), max_channels=ul.get("max_channels"))
        if "vhost" in limits:
            vl = limits["vhost"] or {}
            manager.ensure_vhost_limit(vhost, max_connections=vl.get("max_connections"), max_queues=vl.get("max_queues"))

        for pol in t.get("policies", []) or []:
            if not isinstance(pol, dict):
                raise ValueError(f"policies entries must be objects (tenant '{t['app']}')")
            name = pol.get("name")
            pattern = pol.get("pattern", ".*")
            definition = pol.get("definition", {})
            if not name:
                raise ValueError(f"policy missing 'name' (tenant '{t['app']}')")
            manager.ensure_policy(
                vhost,
                name=name,
                pattern=pattern,
                definition=definition,
                priority=pol.get("priority", 0),
                apply_to=pol.get("apply_to", "all"),
            )

        for param in t.get("parameters", []) or []:
            if not isinstance(param, dict):
                raise ValueError(f"parameters entries must be objects (tenant '{t['app']}')")
            component = param.get("component")
            name = param.get("name")
            value = param.get("value")
            if not component or not name or value is None:
                raise ValueError(f"parameter requires component, name, value (tenant '{t['app']}')")
            manager.ensure_parameter(vhost, component=component, name=name, value=value)


