def parse_args(argv: List[str]) -> argparse.Namespace:
    p = argparse.ArgumentParser(description="Configure RabbitMQ vhosts, users, and permissions via Management HTTP API")
    p.add_argument("--api-url", default=os.environ.get("RABBIT_API_URL", "http://localhost:15672"), help="RabbitMQ management base URL, e.g. http://host:15672")
    p.add_argument("--admin-user", default=os.environ.get("RABBIT_ADMIN_USER", "guest"))
    p.add_argument("--admin-pass", default=os.environ.get("RABBIT_ADMIN_PASS", "guest"))
    p.add_argument("--config", default=os.environ.get("RABBIT_SETUP_CONFIG"), help="Path to JSON config file")
    p.add_argument("--insecure", action="store_true", help="Disable TLS certificate verification")
    p.add_argument("--timeout", type=int, default=int(os.environ.get("RABBIT_API_TIMEOUT", "15")))
    p.add_argument("--wait", action="store_true", help="Wait for management API readiness before applying")
    p.add_argument("--no-fail-missing-password", action="store_true", help="Skip user creation if password not provided and no password_hash")
    p.add_argument("--print-example-config", action="store_true", help="Print example JSON config and exit")
    return p.parse_args(argv)


def main(argv: List[str]) -> int:
    args = parse_args(argv)
    if args.print_example_config:
        sys.stdout.write(json.dumps(example_config(), indent=2) + "\n")
        return 0

    if not args.config:
        sys.stderr.write("ERROR: --config is required (or set RABBIT_SETUP_CONFIG)\n")
        return 2

    cfg_data = load_config(args.config)

    mgr = RabbitMQManager(
        RabbitConfig(
            api_url=args.api_url,
            admin_user=args.admin_user,
            admin_pass=args.admin_pass,
            verify_tls=not args.insecure,
            timeout=args.timeout,
        )
    )

    if args.wait:
        mgr.wait_ready()

    apply(mgr, cfg_data, fail_on_missing_password=not args.no_fail_missing_password)
    return 0


if __name__ == "__main__":
    raise SystemExit(main(sys.argv[1:]))